const API_BASE = '/api'

async function fetchJson<T>(url: string, options?: RequestInit): Promise<T> {
  const response = await fetch(url, options)
  if (!response.ok) {
    throw new Error(`API error: ${response.status} ${response.statusText}`)
  }
  return response.json()
}

export const api = {
  // GET endpoints
  getDashboardData: () => fetchJson<any>(`${API_BASE}/dashboard_data`),
  getLiveScores: () => fetchJson<any>(`${API_BASE}/live_scores`),

  // POST endpoints
  fetchGames: () => fetchJson<any>('/fetch_games', { method: 'POST' }),
  fetchOdds: () => fetchJson<any>('/fetch_odds', { method: 'POST' }),
  postDiscord: () => fetchJson<any>('/post_discord', { method: 'POST' }),
}

export default api
